const response = $input.item.json;
const prev = $('Trigger (chiamato da workflow parent)').item.json;

if (!response.choices?.[0]) {
  throw new Error('Claude prompt optimization fallita: nessuna risposta');
}

const raw = response.choices[0].message.content;
const cleaned = raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
const match = cleaned.match(/\{[\s\S]*\}/);

let parsed;
try {
  parsed = JSON.parse(match ? match[0] : cleaned);
} catch(e) {
  // Se non è JSON valido, usa il testo raw come prompt
  parsed = {
    prompt: `${prev.trigger_word} ${raw.substring(0, 400)}`,
    negative_prompt: 'blurry, deformed, ugly, bad anatomy, extra fingers, watermark, text'
  };
}

return {
  ...prev,
  prompt: parsed.prompt,
  negative_prompt: parsed.negative_prompt || 'blurry, deformed, ugly, bad anatomy, extra fingers, watermark, text, nsfw'
};

const replicateResponse = $input.item.json;
const prev = $('Elabora Prompt').item.json;

const status = replicateResponse.status;
if (status === 'failed' || !replicateResponse.output) {
  throw new Error(`Replicate fallito: ${replicateResponse.error || 'output vuoto'} (status: ${status})`);
}

const imageUrl = Array.isArray(replicateResponse.output)
  ? replicateResponse.output[0]
  : replicateResponse.output;

if (!imageUrl || !imageUrl.startsWith('http')) {
  throw new Error('URL immagine non valido: ' + JSON.stringify(imageUrl));
}

return {
  ...prev,
  image_url: imageUrl,
  replicate_prediction_id: replicateResponse.id,
  generation_time_ms: replicateResponse.metrics?.predict_time
    ? Math.round(replicateResponse.metrics.predict_time * 1000)
    : null
};

