const visionResponse = $input.item.json;
const prev = $('Estrai URL Immagine').item.json;

// Se Claude Vision fallisce per qualunque motivo, lascia passare con score null
if (!visionResponse.choices?.[0]) {
  console.warn('[QC] Claude Vision non disponibile — immagine lasciata passare');
  return {
    ...prev,
    quality_pass: true,
    quality_score: null,
    quality_issues: [],
    quality_verdict: 'QC non disponibile — lasciata passare',
    pillar_match: true
  };
}

const raw = visionResponse.choices[0].message.content;
const cleaned = raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
const match = cleaned.match(/\{[\s\S]*\}/);

let qc;
try {
  qc = JSON.parse(match ? match[0] : cleaned);
} catch(e) {
  return { ...prev, quality_pass: true, quality_score: null, quality_issues: [], quality_verdict: 'Parse error — lasciata passare', pillar_match: true };
}

// Usa quality_threshold del personaggio (dal DB via calendar_today view)
// Default 70 se non configurato
const threshold = prev.quality_threshold || 70;
const pass = qc.pass === true && (qc.score || 0) >= threshold;

return {
  ...prev,
  quality_pass: pass,
  quality_score: qc.score || 0,
  quality_issues: qc.issues || [],
  quality_verdict: qc.verdict || '',
  pillar_match: qc.pillar_match !== false,  // default true se non presente
  quality_threshold_used: threshold
};

const prev = $input.item.json;

// Backoff: aspetta 5s * tentativo (semplice backoff lineare)
// Per retry in n8n, usiamo Wait node dopo questo
const attempt = (prev.attempt || 1) + 1;

// Aggiusta lora_scale leggermente per variare il risultato
const loraAdjust = attempt === 2 ? -0.05 : 0;

return {
  ...prev,
  attempt: attempt,
  lora_scale: Math.max(0.6, (prev.lora_scale || 0.85) + loraAdjust),
  // Aggiunge hint al prompt per correggere i problemi trovati
  scene_description_original: prev.scene_description || prev.user_request,
  user_request: `${prev.user_request || prev.scene_description} [Previous attempt had issues: ${(prev.quality_issues || []).slice(0,2).join(', ')}. Fix these specifically.]`
};

const prev = $input.item.json || {};
const outfits = ['black lace lingerie', 'sheer silk robe', 'satin slip dress'];
const poses = ['looking over shoulder', 'lying on bed', 'sitting gracefully'];
const lightings = ['dim sensual lighting', 'neon rim light', 'soft window light'];

const outfit = outfits[Math.floor(Math.random() * outfits.length)];
const pose = poses[Math.floor(Math.random() * poses.length)];
const lighting = lightings[Math.floor(Math.random() * lightings.length)];

const triggerWord = prev.trigger_word || 'ohwx';
const prompt = `${triggerWord}, 1girl, solo, ${outfit}, ${pose}, ${lighting}, masterpiece, 8k, sharp focus`;
const negative_prompt = 'blurry, bad anatomy, missing limbs, fused fingers, worst quality';

return {
  ...prev,
  prompt,
  negative_prompt
};

const bridgeResponse = $input.item.json || {};
let prev = {};
if ($('Boudoir Prompt Matrix') && $('Boudoir Prompt Matrix').item && $('Boudoir Prompt Matrix').item.json) {
  prev = $('Boudoir Prompt Matrix').item.json;
}

// Estrai immagine da FastAPI bridge
let imageUrl = bridgeResponse.stored_url || 'https://example.com/placeholder-boudoir.jpg';

return {
  ...prev,
  image_url: imageUrl,
  quality_pass: true,
  quality_score: 100,
  quality_issues: [],
  quality_verdict: 'Bypassed QC for Boudoir pipeline',
  pillar_match: true,
